import React from "react";
import { FaBriefcase, FaUniversity, FaCloud } from "react-icons/fa";

const experienceData = [
  { title: "Senior Product Manager", company: "EY", date: "2022-Present", icon: <FaBriefcase />, type: "job" },
  { title: "Certified SAFe® 6 PO/PdM", company: "Scaled Agile", date: "2024", icon: <FaUniversity />, type: "cert" },
  { title: "Certified Scrum PO (CSPO)", company: "Scrum Alliance", date: "2022", icon: <FaUniversity />, type: "cert" },
  { title: "Senior Product Manager", company: "J.P. Morgan", date: "2021-2022", icon: <FaBriefcase />, type: "job" },
  { title: "Azure Fundamentals", company: "Azure", date: "2021", icon: <FaCloud />, type: "cert" },
  { title: "PMI Agile Certified Practitioner", company: "PMI", date: "2019", icon: <FaUniversity />, type: "cert" },
  { title: "Senior Product Manager", company: "ExxonMobil", date: "2014-2021", icon: <FaBriefcase />, type: "job" },
  { title: "Senior Product Owner", company: "ExxonMobil", date: "2013-2014", icon: <FaBriefcase />, type: "job" },
  { title: "Senior Scrum Master", company: "ExxonMobil", date: "2008-2013", icon: <FaBriefcase />, type: "job" },
  { title: "Supervisor", company: "IBM", date: "2001-2008", icon: <FaBriefcase />, type: "job" },
  { title: "Master of Systems Engineering", company: "UTN", date: "2001-2006", icon: <FaUniversity />, type: "edu" },
];

const ExperienceTimeline = () => {
  return (
    <div className="overflow-x-auto py-10 px-6">
      <div className="relative flex items-center min-w-[1200px]">
        {/* Línea central */}
        <div className="absolute top-1/2 left-0 w-full h-1 bg-gray-300 -translate-y-1/2"></div>

        {experienceData.map((item, idx) => {
          const isJob = item.type === "job";

          // Posición vertical de la caja: arriba para jobs, abajo para certificados/educación
          const boxPosition = isJob ? "-top-36" : "top-16";

          // Alinear caja a izquierda o derecha de icono según índice (intercalado)
          const isLeft = idx % 2 === 0;

          // Estilos para caja: color según tipo
          const bgGradient = isJob
            ? "bg-gradient-to-r from-black via-gray-800 to-white text-white"
            : "bg-gradient-to-r from-blue-600 via-blue-300 to-white text-black";

          // Posición de la caja respecto al icono (izquierda o derecha)
          const boxAlignment = isLeft ? "right-0" : "left-0";

          // Para alinear el contenido del texto dentro de la caja (izquierda/derecha)
          const textAlign = isLeft ? "text-right" : "text-left";

          return (
            <div
              key={idx}
              className={`absolute flex flex-col items-center ${boxPosition} w-56 ${isLeft ? "left-[calc((100%/12)*" + idx + ")]" : "left-[calc((100%/12)*" + idx + ") + 4rem]"}`}
              style={{
                transform: "translateX(-50%)",
              }}
            >
              {/* Caja con info */}
              <div
                className={`rounded-lg shadow-lg px-4 py-3 mb-2 w-56 ${bgGradient} ${textAlign}`}
                style={{ minWidth: "14rem" }}
              >
                <p className="text-xs italic opacity-80 mb-1">{item.date}</p>
                <h3 className="font-semibold text-sm">{item.title}</h3>
                <p className="text-xs">{item.company}</p>
              </div>

              {/* Icono */}
              <div className="w-10 h-10 flex items-center justify-center bg-white rounded-full border-2 border-gray-400 shadow-md">
                {item.icon}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default ExperienceTimeline;
